// Construir mensajes de recordatorio 2 horas antes (ya filtradas por PostgreSQL)
const resultados = [];

for (const item of $input.all()) {
  const row = item.json;
  const numero = (row['Número'] || '').toString().trim().replace(/@s\.whatsapp\.net/g, '').replace(/\D/g, '');
  const nombre = (row['Nombre'] || 'cliente').toString().trim();
  const businessName = (row['business_name'] || 'nuestro negocio').toString().trim();
  const professionalName = (row['professional_name'] || '').toString().trim();
  const profLine = professionalName ? `\n👤 *Profesional:* ${professionalName}` : '';
  const hora = (row['Hora'] || '').toString().trim().substring(0,5);
  const servicio = (row['Servicio'] || '').toString().trim();

  if (numero && hora) {
    const mensaje = `Hola ${nombre} 👋\n\n¡Tu cita en *${businessName}* es en 2 horas! ⏰ Hoy a las *${hora}*.\n\n✂️ Servicio: *${servicio}*${profLine}\n\nSi necesitas cancelar o reagendar, responde este mensaje 😊`;
    resultados.push({ json: { numero, nombre, mensaje, hora, servicio } });
  }
}

return resultados;
